  ('police-3fd24912-moex-00079', 'police-3fd24912', 'police-3fd24912-moex-113-15a7b19c', 'sub-police-3fd24912-01', NULL, 'single_choice', '依司法院釋字第798號解釋，財政部以令函限制同一法人於同一行政區域內之分支機構所有 車輛，以3輛為限，始免徵使用牌照稅，係違反下列何者而違憲？', '["憲法第7條之平等權", "憲法第23條之比例原則", "憲法第19條之租稅法律主義", "憲法第19條之實質課稅原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:59+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "504", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "公共安全人員"}'::jsonb, NULL),
