  ('police-3fd24912-moex-00084', 'police-3fd24912', 'police-3fd24912-moex-113-15a7b19c', 'sub-police-3fd24912-01', NULL, 'single_choice', '依司法院釋字第509號解釋意旨，關於誹謗性言論，下列敘述何者正確？', '["不受憲法言論自由之保障", "行為人必須自行證明其言論內容確屬真實，始能免於刑責", "依行為人所提證據資料，認為其有相當理由確信言論內容為真實者，即不構成誹謗罪", "行為人言論內容如經法院調查發現並非真實，即構成誹謗罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:59+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "504", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "公共安全人員"}'::jsonb, NULL),
