  ('police-3fd24912-moex-00088', 'police-3fd24912', 'police-3fd24912-moex-113-15a7b19c', 'sub-police-3fd24912-01', NULL, 'single_choice', '關於憲法第7條男女平等，司法院大法官曾作過的違憲宣告解釋，不包括下列何者？', '["舊民法第 1089 條關於父母對於未成年子女權利之行使意思不一致時，由父行使之規定部 分，違憲", "舊民法第1002條「妻以夫之住所為住所」之規定，違憲", "民法夫妻財產制修正後對修正前已發生之夫妻聯合財產，規定仍由夫繼續享有之部分，違憲", "陸軍官校基於其歷史傳統而以性別為錄取學生之標準，違憲"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:59+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "504", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "公共安全人員"}'::jsonb, NULL)
